const services = [
  { name: "Mobile App MVP",  price: 15000, timeline: "8 weeks",  description: "Full cross-platform flutter app development with core features.",       maxDiscount: "10%", discountLogic: "Offer 10% off for first-time clients only." },
  { name: "Web Development", price: 10000, timeline: "6 weeks",  description: "Custom React-based web application with responsive design.",              maxDiscount: "10%", discountLogic: "Offer 10% off for first-time clients only." },
  { name: "UI/UX Audit",     price: 2500,  timeline: "1 week",   description: "Comprehensive review of user journey and accessibility improvements.",   maxDiscount: "5%",  discountLogic: "Only offer 5% discount if user mentions budget constraints." },
  { name: "Cloud Migration", price: 5000,  timeline: "3 weeks",  description: "Moving legacy infrastructure to AWS or Azure with zero downtime.",       maxDiscount: "0%",  discountLogic: "No discounts allowed for this service." },
  { name: "Discovery Call",  price: 0,     timeline: "30 mins",  description: "Initial free consultation to discuss project scope and goals.",           maxDiscount: "N/A", discountLogic: "Always free — book as a discovery call session, not an order." }
];

const catalogText = services.map(s =>
  `- ${s.name}: $${s.price} | Timeline: ${s.timeline} | ${s.description} | Max Discount: ${s.maxDiscount} | Rule: ${s.discountLogic}`
).join('\n');

return [{ json: { services, catalogText } }];

// Access original webhook data 
const webhookData = $('webhook-chatbot').first().json;
const userMessage  = $('Collect & Merge Burst').first().json.mergedMessage ?? webhookData.body.message ?? webhookData.body.chatInput ?? '';

// sessionId: must come from frontend (stable uuid per user session) 
// Streamlit sends sessionId = 'user_' + uuid4()[:8], stable for full chat
const sessionId = webhookData.body.sessionId ?? 'default-session';
const timestamp  = new Date().toISOString();

// Raw AI Agent output 
const output = $input.first().json.output ?? '';

// Extract INTENT 
const intentMatch = output.match(/INTENT:\s*(\w+)/i);
const intent = intentMatch ? intentMatch[1].toLowerCase().trim() : 'inquiry';

// Extract STATUS 
const statusMatch = output.match(/STATUS:\s*([\w_]+)/i);
const status = statusMatch ? statusMatch[1].toLowerCase().trim() : 'collecting';

// Extract ORDER_DATA JSON 
const orderDataMatch = output.match(/ORDER_DATA:\s*(\{[\s\S]*?\})/i);
let orderData = null;
if (orderDataMatch) {
  try { orderData = JSON.parse(orderDataMatch[1]); }
  catch (e) { orderData = null; }
}

// Extract human-facing reply (strip all metadata blocks) 
let humanReply = output
  .split(/\nINTENT:/i)[0]
  .replace(/SESSION_CONFIRMED[\s\S]*?END_SESSION/gi, '')
  .replace(/ORDER_CONFIRMED[\s\S]*?END_ORDER/gi, '')
  .replace(/ORDER_CANCELLED[\s\S]*?END_CANCELLED/gi, '')
  .replace(/BOOKING_CANCELLED[\s\S]*?END_BOOKING_CANCELLED/gi, '')
  .replace(/\*{1,3}([^*]+)\*{1,3}/g, '$1')
  .replace(/^#+\s+/gm, '')
  .replace(/^[-*]\s+/gm, '')
  .replace(/[ \t]+$/gm, '')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

// ── Extract SESSION_CONFIRMED block 
const sessionMatch = output.match(/SESSION_CONFIRMED\n([\s\S]*?)END_SESSION/i);
let sessionData = null;
if (sessionMatch) {
  const lines = sessionMatch[1].trim().split('\n');
  sessionData = {};
  lines.forEach(line => {
    const colonIdx = line.indexOf(':');
    if (colonIdx !== -1) {
      const key = line.slice(0, colonIdx).trim().toLowerCase().replace(/\s+/g, '_');
      const val = line.slice(colonIdx + 1).trim();
      if (key) sessionData[key] = val;
    }
  });
}

// Extract ORDER_CONFIRMED block 
const orderConfirmedMatch = output.match(/ORDER_CONFIRMED\n([\s\S]*?)END_ORDER/i);
let confirmedOrder = null;
if (orderConfirmedMatch) {
  const lines = orderConfirmedMatch[1].trim().split('\n');
  confirmedOrder = {};
  lines.forEach(line => {
    const colonIdx = line.indexOf(':');
    if (colonIdx !== -1) {
      const key = line.slice(0, colonIdx).trim().toLowerCase().replace(/\s+/g, '_');
      const val = line.slice(colonIdx + 1).trim();
      if (key) confirmedOrder[key] = val;
    }
  });
}

// ── Extract ORDER_CANCELLED block 
const cancelledMatch = output.match(/ORDER_CANCELLED\n([\s\S]*?)END_CANCELLED/i);
let cancelledData = null;
if (cancelledMatch) {
  const lines = cancelledMatch[1].trim().split('\n');
  cancelledData = {};
  lines.forEach(line => {
    const colonIdx = line.indexOf(':');
    if (colonIdx !== -1) {
      const key = line.slice(0, colonIdx).trim().toLowerCase().replace(/\s+/g, '_');
      const val = line.slice(colonIdx + 1).trim();
      if (key) cancelledData[key] = val;
    }
  });
}


// Extract BOOKING_CANCELLED block
const bookingCancelledMatch = output.match(/BOOKING_CANCELLED\n([\s\S]*?)END_BOOKING_CANCELLED/i);
let bookingCancelledData = null;
if (bookingCancelledMatch) {
  const lines = bookingCancelledMatch[1].trim().split('\n');
  bookingCancelledData = {};
  lines.forEach(line => {
    const colonIdx = line.indexOf(':');
    if (colonIdx !== -1) {
      const key = line.slice(0, colonIdx).trim().toLowerCase().replace(/\s+/g, '_');
      const val = line.slice(colonIdx + 1).trim();
      if (key) bookingCancelledData[key] = val;
    }
  });
}
// Override intent/status when session or order is confirmed 
const effectiveIntent = sessionData ? 'booking' : intent;
const effectiveStatus = (sessionData || confirmedOrder) ? 'confirmed' : status;

return [{
  json: {
    humanReply,
    intent:         effectiveIntent,
    status:         effectiveStatus,
    orderData,
    sessionData,
    confirmedOrder,
    cancelledData,
    bookingCancelledData,
    sessionId,
    userMessage,
    timestamp,
    rawOutput: output
  }
}];

