// Sheets API v4 returns:
// { values: [ [row1col1, row1col2, ...], [row2col1, ...], ... ] }
//
// Sheet has a header row at row 1 (index 0). Data rows start at row 2 (index 1).
// Column order (0-based index) based on your sheet screenshot:
//   0: timestamp
//   1: session_id
//   2: product_name
//   3: quantity
//   4: customer_name
//   5: phone
//   6: delivery_address
//   7: final_price
//   8: status

const SESSION_ID_COL = 1; // Column B = index 1

const cancelledData = $('Code in JavaScript').first().json.cancelledData;
const sessionId = (cancelledData && cancelledData.session_id)
  ? cancelledData.session_id.trim()
  : $('Code in JavaScript').first().json.sessionId;
const allRows = $input.first().json.values ?? [];

if (allRows.length === 0) return [{ json: { _notFound: true, _sessionId: sessionId } }];

const matched = [];
for (let i = 0; i < allRows.length; i++) {
  const row = allRows[i];
  const cellVal = String(row[SESSION_ID_COL] ?? '').trim();
  // Skip header row (where session_id column contains the literal 'session_id')
  if (cellVal.toLowerCase() === 'session_id' || cellVal === '') continue;
  if (cellVal === String(sessionId).trim()) {
    // i+1 is the real 1-based spreadsheet row (header is i=0, first data row i=1)
    matched.push({ json: { _rowNumber: i + 1, session_id: row[SESSION_ID_COL] } });
  }
}

if (matched.length === 0) return [{ json: { _notFound: true, _sessionId: sessionId } }];

// Sort descending: delete bottom rows first to avoid index shift
return matched.sort((a, b) => b.json._rowNumber - a.json._rowNumber);

// Sheets API v4 returns:
// { values: [ [row1col1, row1col2, ...], ... ] }
// Booking sheet has a header row at row 1 (index 0). Data rows start at row 2 (index 1).
// Column order (matches Append Booking Sheet):
//   0: timestamp
//   1: session_id  ← SESSION_ID_COL
//   2: customer_name
