// Buffer Burst Message (Debounce Logic) 
const staticData = $getWorkflowStaticData('global');
const body = $input.first().json.body;
const sessionId = body.sessionId ?? 'default-session';
const message = body.message ?? body.chatInput ?? '';
const now = Date.now();

// Initialize buffer structure if needed
if (!staticData.messageBuffer) {
  staticData.messageBuffer = {};
}

const buf = staticData.messageBuffer;

// If no active burst OR the last message was >10s ago (burst expired), start a new burst
if (!buf[sessionId] || (now - buf[sessionId].lastTime) > 10000) {
  const burstId = 'burst_' + sessionId + '_' + now;
  buf[sessionId] = {
    messages: [message],
    startTime: now,
    lastTime: now,
    burstId: burstId
  };
  return [{ json: { isPrimary: true, burstId, sessionId, message, timestamp: new Date().toISOString() } }];
} else {
  // Subsequent burst message — append to buffer, respond immediately
  buf[sessionId].messages.push(message);
  buf[sessionId].lastTime = now;
  const burstId = buf[sessionId].burstId;
  return [{ json: { isPrimary: false, burstId, sessionId, message, timestamp: new Date().toISOString() } }];
}

