// ── Collect & Merge Burst Messages 
const staticData = $getWorkflowStaticData('global');
const bufferData = $('Buffer Burst Message').first().json;
const sessionId = bufferData.sessionId;
const burstId = bufferData.burstId;

const buf = staticData.messageBuffer;
let mergedMessage = '';

if (buf && buf[sessionId] && buf[sessionId].burstId === burstId) {
  // This is still the active burst for this session — collect all and clear
  const messages = buf[sessionId].messages;
  mergedMessage = messages.join(' ');
  // Clear buffer for this session so the next message starts a fresh burst
  delete buf[sessionId];
} else if (buf && buf[sessionId]) {
  // A newer burst started (edge case) — just use the original message
  mergedMessage = bufferData.message;
} else {
  // Buffer already cleared (e.g. only one message) — use original
  mergedMessage = bufferData.message;
}

return [{ json: { sessionId, mergedMessage, timestamp: new Date().toISOString() } }];

const sessionId = $('Code in JavaScript').first().json.sessionId;
const allRows = $input.first().json.values ?? [];

if (allRows.length === 0) return [{ json: { _empty: true } }];

const SESSION_ID_COL = 1;
const matched = [];
for (let i = 0; i < allRows.length; i++) {
  const row = allRows[i];
  const cellVal = String(row[SESSION_ID_COL] ?? '').trim();
  if (cellVal.toLowerCase() === 'session_id' || cellVal === '') continue;
  if (cellVal === String(sessionId).trim()) {
    matched.push({ json: {
      _rowNumber: i + 1,
      timestamp: row[0] ?? '',
      session_id: row[1] ?? '',
      user_message: row[2] ?? '',
      intent: row[3] ?? '',
      status: row[4] ?? '',
      ai_reply: row[5] ?? '',
      order_data: row[6] ?? ''
    }});
  }
}

if (matched.length === 0) return [{ json: { _empty: true } }];

// Sort ascending for chronological append order
return matched.sort((a, b) => a.json._rowNumber - b.json._rowNumber);

// Collect ALL temp rows for this session and merge into ONE Conversations entry
const items = $('Filter Temp By Session').all().filter(i => !i.json._empty);

if (items.length === 0) return [];

// Merge all user_messages in chronological order
const mergedUserMessage = items
  .map(i => (i.json.user_message ?? '').trim())
  .filter(m => m.length > 0)
  .join('. ');

// Use first row for timestamp/session_id, last row for final status/intent/ai_reply/order_data
const first = items[0].json;
const last  = items[items.length - 1].json;

return [{ json: {
  timestamp:    first.timestamp,
  session_id:   first.session_id,
  user_message: mergedUserMessage,
  intent:       last.intent,
  status:       last.status,
  ai_reply:     last.ai_reply,
  order_data:   last.order_data
}}];

// Format Token Usage
// n8n LangChain Agent exposes Gemini usage in several possible paths.
// We try each in order and fall back to text-length estimation.

const codeData   = $('Code in JavaScript').first().json;
const agentRaw   = $('AI Agent').first().json;

// Attempt 1: native Gemini usageMetadata
const um = agentRaw.usageMetadata
        ?? agentRaw.response?.usageMetadata
        ?? agentRaw.generations?.[0]?.[0]?.generationInfo?.usageMetadata
        ?? null;

// Attempt 2: LangChain tokenUsage / llmOutput 
const tu = agentRaw.tokenUsage
        ?? agentRaw.llmOutput?.tokenUsage
        ?? null;

let promptTokens     = 0;
let completionTokens = 0;
let totalTokens      = 0;

if (um) {
  // Gemini native fields
  promptTokens     = um.promptTokenCount     ?? um.inputTokenCount      ?? 0;
  completionTokens = um.candidatesTokenCount ?? um.outputTokenCount     ?? 0;
  totalTokens      = um.totalTokenCount                                  ?? (promptTokens + completionTokens);
} else if (tu) {
  // LangChain unified format
  promptTokens     = tu.promptTokens     ?? 0;
  completionTokens = tu.completionTokens ?? 0;
  totalTokens      = tu.totalTokens      ?? (promptTokens + completionTokens);
} else {
  // Fallback: rough estimation from text length (1 token ≈ 4 chars)
  const promptText = '[SERVICE CATALOG]\n' + ($('Load Service Catalog').first().json.catalogText ?? '') + '\n\n[USER MESSAGE]\n' + (codeData.userMessage ?? '');
  const replyText  = codeData.rawOutput ?? '';
  promptTokens     = Math.ceil(promptText.length / 4);
  completionTokens = Math.ceil(replyText.length  / 4);
  totalTokens      = promptTokens + completionTokens;
}

// Cost: Gemini 2.0 Flash pricing (per-token)
// Input:  $0.075  per 1M tokens  = $0.000000075 per token
// Output: $0.30   per 1M tokens  = $0.0000003   per token
const INPUT_PRICE_PER_TOKEN  = 0.075  / 1_000_000;
const OUTPUT_PRICE_PER_TOKEN = 0.30   / 1_000_000;
const cost = (promptTokens * INPUT_PRICE_PER_TOKEN) + (completionTokens * OUTPUT_PRICE_PER_TOKEN);

return [{ json: {
  timestamp:         codeData.timestamp,
  session_id:        codeData.sessionId,
  user_message:      codeData.userMessage,
  intent:            codeData.intent,
  status:            codeData.status,
  prompt_tokens:     promptTokens,
  completion_tokens: completionTokens,
  total_tokens:      totalTokens,
  cost:              Math.round(cost * 10_000_000) / 10_000_000,  // 7 decimal places
  model:             'gemini-flash'
}}];
